import{_ as a,a as t}from"./chunks/webdav在win显示效果.BVTuSvY9.js";import{_ as i,o as l,c as s,a2 as d}from"./chunks/framework.DnrXFDHb.js";const m=JSON.parse('{"title":"WebDAV Site Access (Beta)","description":"","frontmatter":{},"headers":[],"relativePath":"ur/Safety/webdav-site-access.md","filePath":"ur/Safety/webdav-site-access.md","lastUpdated":1781962217000}'),n={name:"ur/Safety/webdav-site-access.md"};function o(r,e,c,p,h,u){return l(),s("div",null,[...e[0]||(e[0]=[d('<h1 id="webdav-site-access-beta" tabindex="-1">WebDAV Site Access (Beta) <a class="header-anchor" href="#webdav-site-access-beta" aria-label="Permalink to &quot;WebDAV Site Access (Beta)&quot;">​</a></h1><p>Security Settings میں WebDAV setting آپ کی ImgBed site کو WebDAV endpoint کے طور پر expose کرتی ہے۔</p><p>enable ہونے کے بعد آپ Windows، macOS، mobile file managers، یا کوئی بھی WebDAV-compatible client استعمال کر کے ImgBed files کو remote folder کی طرح browse، upload، delete، اور manage کر سکتے ہیں۔</p><p>یہ site کا WebDAV access entry ہے۔ یہ Upload Settings کے WebDAV storage channel سے مختلف ہے۔ upload channel files کو third-party WebDAV service میں store کرتا ہے۔ یہ setting آپ کی ImgBed site کو clients کے لیے WebDAV access provide کرنے دیتی ہے۔</p><h2 id="کہاں-configure-کریں" tabindex="-1">کہاں Configure کریں <a class="header-anchor" href="#کہاں-configure-کریں" aria-label="Permalink to &quot;کہاں Configure کریں&quot;">​</a></h2><p>admin panel کھولیں، پھر جائیں:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings -&gt; WebDAV</span></span></code></pre></div><p>Available settings:</p><ul><li>Enable</li><li>Username</li><li>Password</li><li>Image loading mode</li><li>Default channel</li></ul><h2 id="یہ-feature-کیا-کرتا-ہے" tabindex="-1">یہ Feature کیا کرتا ہے <a class="header-anchor" href="#یہ-feature-کیا-کرتا-ہے" aria-label="Permalink to &quot;یہ Feature کیا کرتا ہے&quot;">​</a></h2><p>WebDAV enabled ہونے کے بعد ImgBed ایک fixed access URL فراہم کرتا ہے:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/dav</span></span></code></pre></div><p>اپنی ImgBed file directory سے connect کرنے کے لیے یہی URL استعمال کریں۔</p><p>اچھے use cases:</p><ul><li>computer file manager سے ImgBed files directly browse کرنا۔</li><li>images کو WebDAV folder میں drag کر کے upload کرنا۔</li><li>local file manager سے ImgBed folders organize کرنا۔</li><li>WebDAV-compatible software سے images sync یا manage کرنا۔</li><li>admin panel کھولے بغیر ImgBed content access کرنا۔</li></ul><h2 id="settings" tabindex="-1">Settings <a class="header-anchor" href="#settings" aria-label="Permalink to &quot;Settings&quot;">​</a></h2><h3 id="enable" tabindex="-1">Enable <a class="header-anchor" href="#enable" aria-label="Permalink to &quot;Enable&quot;">​</a></h3><p>WebDAV endpoint on کرتا ہے۔</p><p>disabled ہو تو clients WebDAV کے ذریعے connect نہیں کر سکتے۔</p><h3 id="username-اور-password" tabindex="-1">Username اور Password <a class="header-anchor" href="#username-اور-password" aria-label="Permalink to &quot;Username اور Password&quot;">​</a></h3><p>WebDAV clients connect کرتے وقت یہی credentials استعمال کرتے ہیں۔</p><p>dedicated WebDAV username اور password استعمال کریں۔ admin password یا upload password دوبارہ استعمال نہ کریں۔</p><p>اگر username یا password میں سے کوئی بھی empty ہو، WebDAV clients صحیح connect نہیں کر پائیں گے۔</p><h3 id="image-loading-mode" tabindex="-1">Image Loading Mode <a class="header-anchor" href="#image-loading-mode" aria-label="Permalink to &quot;Image Loading Mode&quot;">​</a></h3><p>Image loading mode طے کرتا ہے کہ WebDAV clients images پڑھتے وقت کس image URL کو ترجیح دیں۔</p><p>Common choices:</p><table tabindex="0"><thead><tr><th>Mode</th><th>Description</th></tr></thead><tbody><tr><td>Smart loading</td><td>ImgBed context کے مطابق انتخاب کرتا ہے۔ normal use کے لیے recommended۔</td></tr><tr><td>Original</td><td>original images کو ترجیح دیتا ہے۔</td></tr><tr><td>Thumbnail</td><td>thumbnails کو ترجیح دیتا ہے۔ fast preview کے لیے مفید۔</td></tr></tbody></table><p>یقین نہ ہو تو <code>Smart loading</code> رکھیں۔</p><h3 id="default-channel" tabindex="-1">Default Channel <a class="header-anchor" href="#default-channel" aria-label="Permalink to &quot;Default Channel&quot;">​</a></h3><p>default channel WebDAV uploads کے لیے استعمال ہوتا ہے۔</p><p>جب آپ Windows یا کسی client سے WebDAV directory میں files copy کرتے ہیں، ImgBed selected default upload channel کے ذریعے انہیں upload کرتا ہے۔</p><p>اگر default channel selected نہیں، browsing کام کر سکتی ہے، مگر uploads fail ہو سکتے ہیں۔</p><h2 id="windows-11-میں-webdav-access-کرنا" tabindex="-1">Windows 11 میں WebDAV Access کرنا <a class="header-anchor" href="#windows-11-میں-webdav-access-کرنا" aria-label="Permalink to &quot;Windows 11 میں WebDAV Access کرنا&quot;">​</a></h2><p>Windows 11 WebDAV کو network location کے طور پر add کر سکتا ہے۔</p><ol><li><code>This PC</code> کھولیں۔</li><li><code>Add a network location</code> منتخب کریں۔</li><li><code>https://your-domain.com/dav</code> درج کریں۔</li><li>prompt آنے پر اپنا WebDAV username اور password درج کریں۔</li><li>wizard مکمل کریں۔ اس کے بعد WebDAV directory File Explorer میں کھل سکے گی۔</li></ol><p><img src="'+a+'" alt="Add WebDAV in Windows 11" loading="lazy"></p><p>add ہونے کے بعد WebDAV directory Windows File Explorer میں ظاہر ہوتی ہے۔ آپ normal folder کی طرح files open، copy، اور manage کر سکتے ہیں۔</p><p><img src="'+t+'" alt="WebDAV in Windows" loading="lazy"></p><h2 id="supported-operations" tabindex="-1">Supported Operations <a class="header-anchor" href="#supported-operations" aria-label="Permalink to &quot;Supported Operations&quot;">​</a></h2><p>successful WebDAV connection کے بعد عموماً آپ یہ کر سکتے ہیں:</p><ul><li>files اور folders دیکھنا۔</li><li>files upload کرنا۔</li><li>folders بنانا۔</li><li>files یا folders rename کرنا۔</li><li>files move کرنا۔</li><li>files delete کرنا۔</li></ul><p>WebDAV everyday access اور small-scale file management کے لیے بہتر ہے۔ بڑے moves، bulk deletes، یا complex organization کے لیے admin panel استعمال کریں۔</p><h2 id="login-device-management" tabindex="-1">Login Device Management <a class="header-anchor" href="#login-device-management" aria-label="Permalink to &quot;Login Device Management&quot;">​</a></h2><p>successful WebDAV connections Login Device Management کے WebDAV tab میں بھی ظاہر ہوتے ہیں۔</p><p>وہاں آپ WebDAV clients review کر سکتے ہیں اور ضرورت پڑنے پر old devices force offline کر سکتے ہیں۔</p><p>اگر WebDAV username یا password تبدیل کریں، تو old clients کو دوبارہ sign in کرنا ہوگا۔</p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="windows-بار-بار-username-اور-password-مانگتا-ہے" tabindex="-1">Windows بار بار Username اور Password مانگتا ہے <a class="header-anchor" href="#windows-بار-بار-username-اور-password-مانگتا-ہے" aria-label="Permalink to &quot;Windows بار بار Username اور Password مانگتا ہے&quot;">​</a></h3><p>چیک کریں:</p><ul><li>URL <code>https://your-domain.com/dav</code> ہے۔</li><li>username اور password WebDAV settings سے match کرتے ہیں۔</li><li>WebDAV enabled ہے۔</li><li>site HTTPS پر access ہو سکتی ہے۔</li></ul><h3 id="browsing-کام-کرتی-ہے،-مگر-uploading-fail-ہوتی-ہے" tabindex="-1">Browsing کام کرتی ہے، مگر Uploading fail ہوتی ہے <a class="header-anchor" href="#browsing-کام-کرتی-ہے،-مگر-uploading-fail-ہوتی-ہے" aria-label="Permalink to &quot;Browsing کام کرتی ہے، مگر Uploading fail ہوتی ہے&quot;">​</a></h3><p><code>Default channel</code> چیک کریں۔</p><p>WebDAV uploads کو default upload channel چاہیے۔ اگر یہ missing، disabled، یا misconfigured ہو تو uploads fail ہو سکتے ہیں۔</p><h3 id="access-speed-غیر-مستحکم-ہے" tabindex="-1">Access Speed غیر مستحکم ہے <a class="header-anchor" href="#access-speed-غیر-مستحکم-ہے" aria-label="Permalink to &quot;Access Speed غیر مستحکم ہے&quot;">​</a></h3><p>WebDAV performance client، network، file count، اور default upload channel پر depend کرتی ہے۔</p><p>اگر کسی directory میں بہت زیادہ files ہیں، تو انہیں folders میں organize کریں، ایک ہی directory میں بہت زیادہ files نہ رکھیں۔</p><h2 id="security-recommendations" tabindex="-1">Security Recommendations <a class="header-anchor" href="#security-recommendations" aria-label="Permalink to &quot;Security Recommendations&quot;">​</a></h2><ul><li>WebDAV access کے لیے HTTPS استعمال کریں۔</li><li>strong password set کریں۔</li><li>WebDAV password untrusted لوگوں کے ساتھ share نہ کریں۔</li><li>استعمال نہ کر رہے ہوں تو WebDAV off کر دیں۔</li><li>Login Device Management میں unused WebDAV devices وقتاً فوقتاً clean up کریں۔</li></ul><h2 id="webdav-upload-file-size" tabindex="-1">WebDAV Upload File Size <a class="header-anchor" href="#webdav-upload-file-size" aria-label="Permalink to &quot;WebDAV Upload File Size&quot;">​</a></h2><p>WebDAV clients browser upload page کا large-file chunking flow استعمال نہیں کرتے۔ نیچے دی گئی suggested limits سے بڑی files کے لیے web upload page استعمال کریں۔</p><table tabindex="0"><thead><tr><th>Default Upload Channel</th><th style="text-align:right;">Suggested Single-File Limit for WebDAV</th></tr></thead><tbody><tr><td>Telegram</td><td style="text-align:right;">20 MB</td></tr><tr><td>Discord</td><td style="text-align:right;">10 MB</td></tr><tr><td>Cloudflare R2</td><td style="text-align:right;">30 MB</td></tr><tr><td>S3</td><td style="text-align:right;">30 MB</td></tr><tr><td>GitHub Releases</td><td style="text-align:right;">64 MB</td></tr><tr><td>GitLab Packages</td><td style="text-align:right;">64 MB</td></tr><tr><td>Hugging Face</td><td style="text-align:right;">20 MB</td></tr><tr><td>OneDrive</td><td style="text-align:right;">30 MB</td></tr><tr><td>Google Drive</td><td style="text-align:right;">30 MB</td></tr><tr><td>Dropbox</td><td style="text-align:right;">30 MB</td></tr><tr><td>Yandex Disk</td><td style="text-align:right;">30 MB</td></tr><tr><td>pCloud</td><td style="text-align:right;">30 MB</td></tr><tr><td>WebDAV</td><td style="text-align:right;">64 MB</td></tr></tbody></table>',61)])])}const f=i(n,[["render",o]]);export{m as __pageData,f as default};
